mapper.select:
SELECT partner_settlement_id as "settlementId", settlement_month as "settlementMonth", total_sales as "totalSales",
NVL(ROUND(commission_amount / NULLIF(total_sales, 0) * 100), (SELECT commission_rate FROM partner WHERE partner_id = #{partnerId})) as "commissionRate",
commission_amount as "commissionAmount", (total_sales - commission_amount - net_amount) as "partnerCouponAmount", net_amount as "netAmount", status as "status" FROM partner_settlement WHERE partner_id = #{partnerId}
AND settlement_month = #{settleMonth}
AND status = #{status}
ORDER BY settlement_month DESC
